table tr:hover {
    background-color: #f1f1f1;
    cursor: pointer;
}

.tooltip {
    position: relative;
}

.tooltip-text {
    display: none;
    position: absolute;
    background-color: #333;
    color: #fff;
    padding: 5px;
    border-radius: 5px;
}

.tooltip:hover .tooltip-text {
    display: block;
}

table th {
    background-color: #2c3e50;
    color: white;
}

#scroll-to-top {
    position: fixed;
    bottom: 130px; /* Tăng khoảng cách từ dưới lên, hiện tại là 80px */
    right: 20px; /* Khoảng cách từ phải sang */
    display: none;
    padding: 10px 15px;
    background-color: #3498db;
    color: white;
    border: none;
    border-radius: 50%;
    cursor: pointer;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
    transition: background-color 0.3s ease;
    z-index: 5000;
}

#scroll-to-top:hover {
    background-color: #2980b9;
}

/* Dải màu xám cho phần thời gian và marquee */
.header-strip {
    background-color: #2c3e50; /* Màu xám nhạt */
    padding: 10px;
    border-radius: 8px; /* Bo góc mềm mại */
    display: flex;
    justify-content: space-between; /* Đặt các thành phần ở hai bên */
    align-items: center; /* Căn giữa theo chiều dọc */
    margin-bottom: 20px; /* Khoảng cách phía dưới */
    position: relative; /* Định vị dải màu xám */
    overflow: hidden; /* Ẩn phần nội dung vượt ra ngoài */
}

.center-time {
    font-size: 16px;
    color: #ffffff;
    font-weight: bold;
}

.led-marquee {
    font-size: 16px;
    font-weight: bold;
    white-space: nowrap; /* Giữ văn bản trên cùng một dòng */
    margin-left: auto; /* Đẩy văn bản sát rìa bên phải */
    opacity: 0; /* Ban đầu ẩn */
    animation: fade-blink 5s ease-in-out infinite; /* Áp dụng hiệu ứng hiển thị, nhấp nháy và lặp lại */
}

/* Hiệu ứng hiển thị dần lên, nhấp nháy, đổi màu, và biến mất */
@keyframes fade-blink {
    0% {
        opacity: 0; /* Bắt đầu với độ mờ hoàn toàn */
        color: #3498db; /* Màu ban đầu khi ẩn */
    }
    20% {
        opacity: 1; /* Hiển thị rõ */
        color: #e74c3c; /* Đổi màu sang đỏ khi hiện */
    }
    40% {
        opacity: 0; /* Biến mất để tạo hiệu ứng nhấp nháy */
        color: #f1c40f; /* Đổi màu sang vàng trong lúc nhấp nháy */
    }
    60% {
        opacity: 1; /* Hiển thị rõ lại */
        color: #2ecc71; /* Đổi màu sang xanh khi hiển thị lại */
    }
    80% {
        opacity: 0; /* Lại biến mất để tạo thêm hiệu ứng nhấp nháy */
        color: #9b59b6; /* Đổi màu sang tím trong lúc nhấp nháy */
    }
    100% {
        opacity: 1; /* Kết thúc với việc hiển thị lại */
        color: #3498db; /* Đổi lại màu xanh dương khi kết thúc */
    }
}

/* Dải hiển thị Lịch học hôm nay */
.schedule-strip {
    background-color: #373737; /* Màu nền nhạt */
    padding: 15px;
    border-radius: 8px; /* Bo góc mềm mại */
    margin-top: 20px; /* Khoảng cách phía trên */
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1); /* Bóng đổ nhẹ */
    text-align: center; /* Căn giữa văn bản */
}

.schedule-strip h3 {
    margin: 0;
    font-size: 18px;
    color: #ffffff;
}

.schedule-strip #schedule-details {
    font-weight: bold;
    color: #2ecc71; /* Màu xanh lá cho lịch học nếu có */
}

#schedule-body tr {
    opacity: 0;
    transition: opacity 0.5s ease-in-out;
}

#schedule-body tr.visible {
    opacity: 1;
}

/* Hiệu ứng mượt mà cho pop-up */
.floating-popup {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -60%); /* Dịch chuyển lên một chút khi chưa hiển thị */
    background-color: white;
    padding: 20px;
    border-radius: 10px;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
    z-index: 10000;
    text-align: center;
    opacity: 0;
    transition: opacity 0.5s ease-in-out, transform 0.5s ease-in-out; /* Chuyển tiếp cho hiệu ứng mờ và dịch chuyển */
    display: none;
}

/* Hiệu ứng hiển thị */
.floating-popup.show {
    display: block;
    opacity: 1;
    transform: translate(-50%, -50%); /* Hiển thị ở giữa màn hình */
}

/* Hiệu ứng ẩn */
.floating-popup.hide {
    opacity: 0;
    transform: translate(-50%, -60%); /* Dịch chuyển lên một chút khi ẩn */
}

#today-schedule-gif {
    display: block;
    margin: 20px auto; /* Căn giữa theo chiều ngang */
    max-width: 100%; /* Đảm bảo ảnh không vượt quá kích thước của phần tử cha */
}

#weather {
    font-size: 16px;
    color: #ffffff;
    font-weight: bold;
    margin-left: 20px;
    display: flex;
    align-items: center;
}
#weather img {
    margin-right: 5px;
}

.fade-in {
    animation: fadeIn 0.5s;
}

@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

/* The switch - the box around the slider */
.switch {
    position: relative;
    display: inline-block;
    width: 60px;
    height: 34px;
  }

  /* Hide default HTML checkbox */
  .switch input {
    opacity: 0;
    width: 0;
    height: 0;
  }

  /* The slider */
  .slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: #ccc;
    -webkit-transition: .4s;
    transition: .4s;
  }

  .slider:before {
    position: absolute;
    content: "";
    height: 26px;
    width: 26px;
    left: 4px;
    bottom: 4px;
    background-color: white;
    -webkit-transition: .4s;
    transition: .4s;
  }

  input:checked + .slider {
    background-color: #2196F3;
  }

  input:focus + .slider {
    box-shadow: 0 0 1px #2196F3;
  }

  input:checked + .slider:before {
    -webkit-transform: translateX(26px);
    -ms-transform: translateX(26px);
    transform: translateX(26px);
  }

  /* Rounded sliders */
  .slider.round {
    border-radius: 34px;
  }

  .slider.round:before {
    border-radius: 50%;
  }

  /* Dark mode styles */
  body.dark-mode {
    background-color: #121212;
    color: #e0e0e0;
  }

  .dark-mode .form-container, .dark-mode .header-strip, .dark-mode .schedule-strip {
    background-color: #333;
  }

  .dark-mode table, .dark-mode th, .dark-mode td {
    background-color: #444;
    color: #e0e0e0;
  }

/* Kiểu chữ cho Chế độ tối/sáng */
#dark-mode-label {
    font-size: 16px;
    color: #ffffff;
    font-weight: bold;
    margin-left: 10px;
    vertical-align: middle; /* Giúp căn giữa theo chiều dọc với nút */
    transition: color 0.3s ease;
}

/* Kiểu cho biểu tượng */
#mode-icon {
    margin-right: 5px;
    transition: transform 0.3s ease, color 0.3s ease;
}

/* Đổi màu chữ khi ở chế độ nền tối */
body.dark-mode #dark-mode-label {
    color: #e0e0e0;
}

body.dark-mode #mode-icon {
    color: #f0e68c; /* Màu vàng nhạt cho biểu tượng mặt trăng */
}

/* Kiểu cho các ô lọc nâng cao */
.filter-container select, .filter-container input {
    margin-right: 10px;
    padding: 10px;
    border-radius: 5px;
    border: 1px solid #ccc;
}

/* Kiểu cho hộp gợi ý */
.suggestion-box {
    border: 1px solid #ccc;
    border-radius: 5px;
    background-color: #fff;
    position: absolute;
    z-index: 1000;
    width: 300px;
    display: none;
}

.suggestion-item {
    padding: 10px;
    cursor: pointer;
}

.suggestion-item:hover {
    background-color: #f0f0f0;
}

/* Chatbox CSS */
/* Điều chỉnh vị trí hộp chat để dịch sang trái */
.chatbox {
    position: fixed;
    bottom: 100px; /* Giữ khoảng cách từ dưới để không đè lên biểu tượng liên hệ */
    right: 100px; /* Dịch hộp chat sang trái xa hơn */
    width: 300px;
    background-color: white;
    border-radius: 10px;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
    display: none;
    flex-direction: column;
    z-index: 1002; /* Đảm bảo hộp chat nằm trên tất cả các phần tử khác */
}

.chatbox-header {
    padding: 10px;
    background-color: #3498db;
    color: white;
    border-radius: 10px 10px 0 0;
    display: flex;
    justify-content: space-between;
}

.chatbox-body {
    padding: 10px;
    height: 200px;
    overflow-y: auto;
    font-size: 14px;
