    msgElement.className = sender;
    msgElement.textContent = message;
    chatBody.appendChild(msgElement);
    chatBody.scrollTop = chatBody.scrollHeight
}

function processChatMessage(message) {
    if (message.includes("lịch học hôm nay")) {
        const todaySchedule = getTodaySchedule();
        addChatMessage("bot", `Lịch học hôm nay của bạn: ${todaySchedule}`);
        speak(`Lịch học hôm nay của bạn: ${todaySchedule}`)
    } else if (message.includes("thời tiết")) {
        fetchWeather()
    } else if (message.includes("hướng dẫn")) {
        addChatMessage("bot", "Bạn có thể tìm kiếm lịch học, xem thời tiết và nhiều tính năng khác.");
        speak("Bạn có thể tìm kiếm lịch học, xem thời tiết và nhiều tính năng khác.")
    } else {
        addChatMessage("bot", "Xin lỗi, tôi không hiểu câu hỏi của bạn.")
    }
}

